Rule.Source:
  
	import sailpoint.tools.Util;
	import sailpoint.object.QueryOptions;
	import sailpoint.object.Filter;
	import sailpoint.object.Identity;
	  
	  String corrID = account.getStringAttribute("CorrID") ;
	  
	  Map returnMap = new HashMap();
	  
	  if(Util.isNotNullOrEmpty(corrID))
	  {
		//--search samAccountName for matches first--
		QueryOptions qryOpt = new QueryOptions();
		qryOpt.addFilter(Filter.eq("samAccountName", corrID));

		matchedIdentities = context.search(Identity.class, qryOpt, "name");
		
			
		//--if no matches from samAccountName search, search Cube Name next--
		if(!matchedIdentities.hasNext())
		{
			QueryOptions qryOpt = new QueryOptions();
			qryOpt.addFilter(Filter.eq("name", corrID));

			matchedIdentities = context.search(Identity.class, qryOpt, "name");
		}     
		
		
		//--if no matches from ANY ministry, search links.displayName with links.application.type of 'Active Directory - Direct' last, using Filter.MatchMode.END--
		if(!matchedIdentities.hasNext())
		{
			String adApplicationType = "Active Directory - Direct" ;
			Filter linksApplicationTypeFilter = Filter.eq("links.application.type", adApplicationType) ; 
			Filter linksDisplayNameFilter = Filter.like("links.displayName", "\\"+corrID, Filter.MatchMode.END);
	  
			Filter finalFilter = Filter.and(linksApplicationTypeFilter,linksDisplayNameFilter) ;
			qryOpt = new QueryOptions();
			qryOpt.addFilter(finalFilter);
		  
			matchedIdentities = context.search(Identity.class, qryOpt, "name");     
		}

		//--if any match was found, add it to the returnMap variable--
		if (matchedIdentities != null) 
		{
			while (matchedIdentities.hasNext())
			{
				Object[] row = (Object[]) matchedIdentities.next();
				String matchedIdentityCubeName = row[0];
				returnMap.put("identityName",matchedIdentityCubeName);
			}
		}
		Util.flushIterator(matchedIdentities);
	}
	return returnMap;
